Here's how to create a custom useForm hook for validation:

1. Create the hook with state for values and errors
2. Define validation rules as a schema
3. Validate on submit and on change

```typescript
function useForm<T>(initialValues: T, validate: (values: T) => Record<string, string>) {
  const [values, setValues] = useState(initialValues);
  const [errors, setErrors] = useState<Record<string, string>>({});

  const handleChange = (name: keyof T, value: any) => {
    setValues(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (onSubmit: (values: T) => void) => {
    const validationErrors = validate(values);
    setErrors(validationErrors);
    if (Object.keys(validationErrors).length === 0) {
      onSubmit(values);
    }
  };

  return { values, errors, handleChange, handleSubmit };
}
```

For more complex validation, consider using Zod with a custom hook.

Sure! Here's the Zod integration:

```typescript
import { z } from 'zod';

const loginSchema = z.object({
  email: z.string().email('Invalid email'),
  password: z.string().min(8, 'Password must be at least 8 characters'),
});

function useZodForm<T extends z.ZodType>(schema: T, initialValues: z.infer<T>) {
  const [values, setValues] = useState(initialValues);
  const [errors, setErrors] = useState<Record<string, string>>({});

  const validate = () => {
    const result = schema.safeParse(values);
    if (!result.success) {
      const fieldErrors: Record<string, string> = {};
      result.error.issues.forEach(issue => {
        fieldErrors[issue.path[0] as string] = issue.message;
      });
      setErrors(fieldErrors);
      return false;
    }
    setErrors({});
    return true;
  };

  return { values, errors, setValues, validate };
}
```

This gives you type-safe validation with clear error messages.
